SELECT /* @SQLID=SUB00_02-06_1#Sql002 */ SUB.* FROM ( SELECT COUNT(*) OVER () AS TOTAL_COUNT ,LPAD(SBC_NO,6,'0') AS SBC_NO ,TO_CHAR(UPDATE_TIME, 'yyyy/mm/dd') AS UPDATE_DATE ,TO_CHAR(CREATE_TIME, 'yyyy/mm/dd') AS CREATE_DATE ,TITLE ,CATEGORY ,STATUS ,SUGGESTION FROM SUG_BOX_COMMON WHERE TO_DATE(TO_CHAR(CREATE_TIME, 'yyyy/mm/dd'), 'yyyy/mm/dd') BETWEEN TO_DATE(#{req.registerDateFrom}, 'yyyy/mm/dd') AND TO_DATE(#{req.registerDateTo}, 'yyyy/mm/dd')
AND TITLE LIKE '%' || #{req.title} || '%'
AND STATUS = #{req.status}
ORDER BY SBC_NO ASC ) SUB WHERE ROWNUM <= #{req.maxRowNum}
